# Health check endpoint (less restrictive rate limit)
@app.route('/api/health', methods=['GET'])
@limiter.limit("10 per minute")
def health_check():
    try:
        es_healthy = es.ping()
    except Exception:
        es_healthy = False

    status = "healthy" if es_healthy else "degraded"
    status_code = 200 if es_healthy else 503

    return jsonify({"status": status}), status_code


